// Calculate the total sum of a list (context)
@function list-sum($list)
  // zero out the initial sum
  $sum: 0
  // loop through each value in the list adding it to $list-sum
  @for $i from 1 through length($list)
    $sum: $sum + nth(nth($list, $i), 1)
  @return nth($sum, 1)


// Find column count
@function column-count($columns)
  @if type-of($columns) == number
    @return $columns
  @if type-of($columns) == list
    @return length($columns)


// Context of gutters
@function gutter-context($gutter, $context)
  @return $gutter * (100% / $context)

@function repeat($count, $repeat)
  $list: $repeat
  @for $i from 2 through $count
    $list: join($repeat, $list)
  @return $list

// Reverses direction of a list
@function reverse($list)
  $length: length($list)
  $return: ()

  @for $i from 0 to $length
    $return: append($return, nth($list, $length - $i), comma)

  @return $return

// This file serves as the "skeleton" of the theming logic.
//
// This contains the bulk of the logic for handling dark mode, color scheme
// toggling and the handling of color-scheme-specific hiding of elements.

body
  @include fonts
  @include spacing
  @include icons
  @include admonitions
  @include default-admonition(#651fff, "abstract")
  @include default-topic(#14B8A6, "pencil")

  @include colors

.only-light
  display: block !important
.only-dark
  display: none !important

// Enable dark-mode, if requested.
body[data-theme="dark"]
  @include colors-dark

  .only-light
    display: none !important
  .only-dark
    display: block !important

// Enable dark mode, unless explicitly told to avoid.
@media (prefers-color-scheme: dark)
  body:not([data-theme="light"])
    @include colors-dark

    .only-light
      display: none !important
    .only-dark
      display: block !important

//
// Theme toggle presentation
//
body[data-theme="auto"]
  .theme-toggle svg.theme-icon-when-auto
    display: block

body[data-theme="dark"]
  .theme-toggle svg.theme-icon-when-dark
    display: block

body[data-theme="light"]
  .theme-toggle svg.theme-icon-when-light
    display: block

